let raw = $json.content[0].text.trim();

// Strip markdown code fences if Claude adds them anyway
if (raw.startsWith('```')) {
  raw = raw.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error('Claude returned invalid JSON: ' + raw.substring(0, 200));
}

const vaId = $('Split VAs - one at a time').item.json.id;

return [{
  json: {
    vaId,
    years_of_experience: parsed.years_of_experience ?? null,
    english_proficiency: parsed.english_proficiency ?? 'Unknown',
    summary: parsed.summary ?? '',
    skills: parsed.skills ?? [],
    tools: parsed.tools ?? []
  }
}];

const data = $input.item.json;
return data.skills.map(skill => ({
  json: {
    vaId: data.vaId,
    name: skill.name,
    category: skill.category,
    proficiency: skill.proficiency
  }
}));

const data = $input.item.json;
return data.tools.map(tool => ({
  json: {
    vaId: data.vaId,
    name: tool.name,
    category: tool.category,
    proficiency: tool.proficiency
  }
}));

const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = binaryData.toString('base64');

const body = {
  model: "claude-sonnet-4-5",
  max_tokens: 2048,
  messages: [
    {
      role: "user",
      content: [
        {
          type: "document",
          source: {
            type: "base64",
            media_type: "application/pdf",
            data: base64
          }
        },
        {
          type: "text",
          text: `Extract information from this VA resume. Return ONLY a valid JSON object. No markdown, no code fences, no backticks, no explanation. Start your response with { and end with }.

Use exactly this schema:
{
  "years_of_experience": <integer>,
  "english_proficiency": "Native | Fluent | Intermediate | Basic | Unknown",
  "summary": "<2-3 sentence professional summary>",
  "skills": [
    { "name": "<skill name>", "category": "<Admin & ops | Communication | Content writing | Research | Customer support>", "proficiency": "<Beginner | Intermediate | Advanced | Expert>" }
  ],
  "tools": [
    { "name": "<tool name>", "category": "<Project management | CRM | Design | Communication | Accounting | AI tools>", "proficiency": "<Beginner | Intermediate | Advanced | Expert>" }
  ]
}`
        }
      ]
    }
  ]
};

return [{
  json: {
    vaId: $('Split VAs - one at a time').item.json.id,
    claudeBody: JSON.stringify(body)
  }
}];
